import api from "./api";
import { getUserFromLocalStorage } from "./authService";

// Lấy tất cả sự kiện, cho phép truyền vào tham số cho Admin/User
export const getAllEvents = async (isAdmin = false) => {
  const endpoint = isAdmin ? "/admin/events" : "/events"; // Dựa vào tham số isAdmin để gọi đúng API
  const headers = getUserFromLocalStorage(); // Lấy token từ localStorage nếu có
  return await api.get(endpoint, { headers }); // Gọi API với token nếu có
};

// Lấy sự kiện theo ID
export const getEventById = async (id, isAdmin = false) => {
  const endpoint = isAdmin ? `/admin/events/${id}` : `/events/${id}`;
  const headers = getUserFromLocalStorage();
  return await api.get(endpoint, { headers });
};

// Lấy chi tiết sự kiện kèm vé
export const getEventDetailWithTickets = async (id, isAdmin = false) => {
  const endpoint = isAdmin ? `/admin/events/${id}/details` : `/events/${id}/details`;
  const headers = getUserFromLocalStorage();
  return await api.get(endpoint, { headers });
};

// Quản trị viên tạo sự kiện
export const adminCreateEvent = (data) => {
  const headers = getUserFromLocalStorage();
  return api.post("/admin/events", data, { headers });
};

// Quản trị viên cập nhật sự kiện
export const adminUpdateEvent = (id, data) => {
  const headers = getUserFromLocalStorage();
  return api.put(`/admin/events/${id}`, data, { headers });
};

// Quản trị viên xóa sự kiện
export const adminDeleteEvent = (id) => {
  const headers = getUserFromLocalStorage();
  return api.delete(`/admin/events/${id}`, { headers });
};
